import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"19. Part Time Employment","description":"","frontmatter":{"title":"19. Part Time Employment","eba":"Biomedical Engineers 2025-2028","topics":["hours","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/employment/19-part-time-employment.md","filePath":"ebas/biomedical-engineers/employment/19-part-time-employment.md"}'),n={name:"ebas/biomedical-engineers/employment/19-part-time-employment.md"};function s(i,e,p,l,m,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_19-part-time-employment" tabindex="-1">19. Part Time Employment <a class="header-anchor" href="#_19-part-time-employment" aria-label="Permalink to &quot;19. Part Time Employment&quot;">​</a></h1><p><strong>19.1</strong> A part-time Employee is an Employee who:</p><p><strong>(a)</strong> works less than an average of 38 hours per week; and</p><p><strong>(b)</strong> has reasonably predictable hours of work.</p><p><strong>19.2</strong> Before commencing employment, the Employer and Employee will agree in writing on a regular pattern of work including the:</p><p><strong>(a)</strong> number of hours to be worked each week;</p><p><strong>(b)</strong> days of the week the employee will work; and</p><p><strong>(c)</strong> starting and finishing times each day.</p><p><strong>19.3</strong> The terms of the agreement in clause 19.2 may be varied by agreement and recorded in writing.</p><p><strong>19.4</strong> A part-time Employee may be employed on either an ongoing or fixed term basis.</p><p><strong>19.5</strong> Entitlements The terms of this Agreement apply to part-time Employees on the basis that the ordinary weekly hours for full-time Employees are 38, including:</p><p><strong>(a)</strong> payment at an hourly rate equal to 1/38th of the weekly rate appropriate for the Employee’s classification; and</p><p><strong>(b)</strong> leave entitlements on a pro rata basis.</p><p><strong>19.6</strong> Additional hours</p><p><strong>(a)</strong> A part time Employee may be offered additional hours at the applicable ordinary time rates for the time worked, within the limits prescribed by this Agreement.</p><p><strong>(b)</strong> A part-time Employee is entitled to decline an offer of additional ordinary hours.</p><p><strong>(c)</strong> Where a part-time Employee is directed by the Employer to work reasonable additional hours, or works hours in excess of 38 in a week, an average of 38 hours a week or the limits prescribed by the Agreement, overtime rates will apply.</p><p><strong>19.7</strong> Part Time Hours Review</p><p><strong>(a)</strong> Where over a period of 26 weeks or more a part-time Employee regularly and/or systematically works more than their contracted hours, the Employer or the Employee may request in writing a contract variation reflecting that the Employee’s hours have increased on a permanent basis. Such a request will not be unreasonably refused by either party.</p><p><strong>(b)</strong> Where the Employer makes the request under subclause 19.7(a), at the time of making the request the Employer will also notify the Employee in writing of their obligations under this subclause 19.7.</p><p><strong>(c)</strong> An Employee will not be considered to be regularly and/or systematically rostered if the shifts the Employee has been working are replacing an absent Employee (for example parental leave, long service leave, or workers’ compensation), a temporary flexible work arrangement or other fixed-term arrangement.</p><p><strong>(d)</strong> A written response will be provided no later than 21 days from the date of a request (by either an Employee or Employer). Where the request is refused, the written response will include reasons for the refusal.</p><p><strong>(e)</strong> Where such a conversion occurs, the Employee will be provided with a Letter of Appointment setting out the revised employment arrangements.</p><p>Plain language terms: part-time, PT.</p>',24)])])}const y=t(n,[["render",s]]);export{d as __pageData,y as default};
